package qrspicmd

import (
	"bufio"
	"bytes"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

type sessionEntry struct {
	Type    string          `json:"type"`
	ID      string          `json:"id,omitempty"`
	Cwd     string          `json:"cwd,omitempty"`
	Message *sessionMessage `json:"message,omitempty"`
}

type sessionMessage struct {
	Role       string          `json:"role"`
	Content    json.RawMessage `json:"content"`
	StopReason string          `json:"stopReason,omitempty"`
}

type sessionContentBlock struct {
	Type string `json:"type"`
	Text string `json:"text,omitempty"`
}

func ResolveSessionPath(sessionDir, sessionID, cwd string) (string, error) {
	if strings.TrimSpace(sessionDir) == "" || strings.TrimSpace(sessionID) == "" {
		return "", errors.New("session dir and session id are required")
	}

	if _, err := os.Stat(sessionDir); err != nil {
		if os.IsNotExist(err) {
			return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
		}
		return "", err
	}

	var matches []string
	walkErr := filepath.WalkDir(
		sessionDir,
		func(path string, entry os.DirEntry, err error) error {
			if err != nil {
				return err
			}
			if entry.IsDir() || filepath.Ext(entry.Name()) != ".jsonl" {
				return nil
			}
			header, err := readSessionHeader(path)
			if err != nil {
				return nil
			}
			if header.Type == "session" && header.ID == sessionID &&
				(strings.TrimSpace(cwd) == "" || header.Cwd == cwd) {
				matches = append(matches, path)
			}
			return nil
		},
	)
	if walkErr != nil {
		return "", walkErr
	}

	switch len(matches) {
	case 1:
		return matches[0], nil
	case 0:
		return "", fmt.Errorf("session %q not found in %s", sessionID, sessionDir)
	default:
		return "", fmt.Errorf(
			"session %q matched multiple files in %s",
			sessionID,
			sessionDir,
		)
	}
}

func readSessionHeader(path string) (sessionEntry, error) {
	file, err := os.Open(path)
	if err != nil {
		return sessionEntry{}, err
	}
	defer file.Close()

	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	if !scanner.Scan() {
		if err := scanner.Err(); err != nil {
			return sessionEntry{}, err
		}
		return sessionEntry{}, errors.New("empty session file")
	}
	var header sessionEntry
	if err := json.Unmarshal(bytes.TrimSpace(scanner.Bytes()), &header); err != nil {
		return sessionEntry{}, err
	}
	return header, nil
}

func ExtractFinalAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, true)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf(
			"session %s has no assistant text containing qrspi_result",
			path,
		)
	}
	return last, nil
}

func ExtractLastAssistantTextFromSession(path string) (string, error) {
	last, err := extractLastAssistantTextFromSession(path, false)
	if err != nil {
		return "", err
	}
	if last == "" {
		return "", fmt.Errorf("session %s has no assistant text", path)
	}
	return last, nil
}

func extractLastAssistantTextFromSession(
	path string,
	requireQRSPIResult bool,
) (string, error) {
	file, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer file.Close()

	var last string
	scanner := bufio.NewScanner(file)
	scanner.Buffer(make([]byte, 64*1024), 1024*1024)
	for scanner.Scan() {
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var entry sessionEntry
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry.Type != "message" || entry.Message == nil ||
			entry.Message.Role != "assistant" {
			continue
		}
		if requireQRSPIResult &&
			(entry.Message.StopReason == "error" || entry.Message.StopReason == "aborted") {
			continue
		}
		text := textBlocksFromAssistantMessage(*entry.Message)
		if strings.TrimSpace(text) == "" {
			continue
		}
		if !requireQRSPIResult || strings.Contains(text, "qrspi_result") {
			last = text
		}
	}
	if err := scanner.Err(); err != nil {
		return "", err
	}
	return last, nil
}

func textBlocksFromAssistantMessage(msg sessionMessage) string {
	var blocks []sessionContentBlock
	if err := json.Unmarshal(msg.Content, &blocks); err == nil {
		var parts []string
		for _, block := range blocks {
			if block.Type == "text" && block.Text != "" {
				parts = append(parts, block.Text)
			}
		}
		return strings.Join(parts, "\n")
	}

	var text string
	if err := json.Unmarshal(msg.Content, &text); err == nil {
		return text
	}
	return ""
}

package qrspicmd

import (
	"context"
	"fmt"
	"os"
	"strings"
)

func InspectActiveChildHealth(
	ctx context.Context,
	state ManagerState,
	stateFile string,
	d deps,
) (ActiveChildHealth, error) {
	if state.ActiveChild == nil {
		return ActiveChildHealth{
			Status:   ActiveChildUnknown,
			Evidence: []string{"no active child"},
		}, nil
	}
	child := state.ActiveChild
	health := ActiveChildHealth{
		Status:      ActiveChildUnknown,
		ChildID:     child.ID,
		Stage:       child.Stage,
		PaneID:      child.TmuxPaneID,
		OutputPath:  child.OutputPath,
		StatusPath:  child.StatusPath,
		DonePath:    child.DonePath,
		SessionDir:  child.SessionDir,
		SessionPath: child.SessionPath,
		SafeCommand: fmt.Sprintf(
			"vamos qrspi repair-state --state-file %s --clear-failed-child --relaunch",
			stateFile,
		),
	}

	status, _ := ReadChildStatus(child.StatusPath)
	if status != nil {
		health.ExitCode = &status.ExitCode
		health.Evidence = append(
			health.Evidence,
			fmt.Sprintf("exitCode: %d", status.ExitCode),
		)
	}
	if data, err := os.ReadFile(child.OutputPath); err == nil {
		health.OutputTail = FilterChildOutputTail(data, 8)
	}

	hasResult, sessionPath, resultErr := ChildHasQRSPIResult(state)
	if hasResult {
		health.Status = ActiveChildFinishedNeedsValidation
		health.SessionPath = sessionPath
		health.Evidence = append(health.Evidence, "session has qrspi_result")
		return health, nil
	}
	if strings.TrimSpace(sessionPath) != "" {
		health.SessionPath = sessionPath
	} else if resolved, err := resolveActiveChildSessionPath(child); err == nil {
		health.SessionPath = resolved
	}
	sessionText := ""
	if strings.TrimSpace(health.SessionPath) != "" {
		if text, err := ExtractLastAssistantTextFromSession(
			health.SessionPath,
		); err == nil {
			sessionText = text
		}
	}

	paneOK := false
	if strings.TrimSpace(child.TmuxPaneID) != "" {
		ok, err := tmuxClient(d).PaneExists(ctx, TmuxPane{ID: child.TmuxPaneID})
		paneOK = ok && err == nil
		if !paneOK {
			health.Evidence = append(health.Evidence, "pane missing")
		}
	}
	if status != nil && HasDoneMarker(child.DonePath) && !hasResult &&
		HasChildContextExhaustionEvidence(health, sessionText) {
		health.Status = ActiveChildContextExhausted
		if resultErr != nil {
			health.Evidence = append(health.Evidence, resultErr.Error())
		}
		if strings.TrimSpace(sessionText) != "" {
			health.Evidence = append(
				health.Evidence,
				"session has context-limit/no-result evidence",
			)
		}
		health.SafeCommand = fmt.Sprintf(
			"pi --resume %s # then run /compact only if this is the exhausted child session",
			firstNonEmpty(health.SessionPath, child.SessionID),
		)
		return health, nil
	}
	if status != nil && status.ExitCode != 0 && HasDoneMarker(child.DonePath) &&
		!hasResult {
		health.Status = ActiveChildLaunchFailed
		if resultErr != nil {
			health.Evidence = append(health.Evidence, resultErr.Error())
		}
		return health, nil
	}
	if status != nil && status.ExitCode == 0 && HasDoneMarker(child.DonePath) {
		health.Status = ActiveChildFinishedNeedsValidation
		return health, nil
	}
	if !paneOK && strings.TrimSpace(child.TmuxPaneID) != "" {
		health.Status = ActiveChildPaneMissing
		return health, nil
	}
	health.Status = ActiveChildRunning
	health.Evidence = append(
		health.Evidence,
		"pane exists and no terminal failure status",
	)
	return health, nil
}

func HasDoneMarker(path string) bool {
	if strings.TrimSpace(path) == "" {
		return false
	}
	_, err := os.Stat(path)
	return err == nil
}

func ChildHasQRSPIResult(state ManagerState) (bool, string, error) {
	text, parseCtx, err := ReadChildResultText(state, ResultSourceOptions{})
	if err != nil {
		return false, "", err
	}
	return strings.Contains(text, "qrspi_result"), parseCtx.SessionPath, nil
}

func HasChildContextExhaustionEvidence(
	health ActiveChildHealth,
	sessionText string,
) bool {
	lines := append([]string{}, health.Evidence...)
	lines = append(lines, health.OutputTail...)
	if strings.TrimSpace(sessionText) != "" {
		lines = append(lines, sessionText)
	}
	needles := []string{
		"context length",
		"context window",
		"context_length_exceeded",
		"maximum context",
		"context limit",
		"compaction failed",
	}
	for _, line := range lines {
		text := strings.ToLower(line)
		for _, needle := range needles {
			if strings.Contains(text, needle) {
				return true
			}
		}
	}
	return false
}

func resolveActiveChildSessionPath(child *ChildRunRef) (string, error) {
	if child == nil {
		return "", fmt.Errorf("no active child")
	}
	if strings.TrimSpace(child.SessionPath) != "" {
		return strings.TrimSpace(child.SessionPath), nil
	}
	return ResolveSessionPath(child.SessionDir, child.SessionID, child.Cwd)
}

func IsTerminalFailedChild(health ActiveChildHealth) bool {
	return health.Status == ActiveChildLaunchFailed
}

func IsRecoverableNoResultChild(health ActiveChildHealth) bool {
	return health.Status == ActiveChildContextExhausted
}

import { spawn } from "node:child_process";
import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname } from "node:path";

async function writeJson(path, value) {
  if (!path) return;
  await mkdir(dirname(path), { recursive: true });
  await writeFile(path, `${JSON.stringify(value, null, 2)}\n`, "utf8");
}

async function readJson(path) {
  if (!path) return null;
  try {
    return JSON.parse(await readFile(path, "utf8"));
  } catch (error) {
    if (error && error.code === "ENOENT") return null;
    return null;
  }
}

async function touch(path) {
  if (!path) return;
  await mkdir(dirname(path), { recursive: true });
  await writeFile(path, "", "utf8");
}

async function runChildComplete() {
  const stateFile = process.env.Q_MANAGER_STATE_FILE || "";
  const childID = process.env.Q_MANAGER_CHILD_ID || "";
  if (!stateFile || !childID) return null;
  return new Promise((resolve) => {
    const child = spawn(
      "vamos",
      [
        "qrspi",
        "child-complete",
        "--state-file",
        stateFile,
        "--child-id",
        childID,
        "--output",
        "json",
      ],
      { stdio: ["ignore", "pipe", "pipe"] },
    );
    let stdout = "";
    child.stdout.on("data", (chunk) => {
      stdout += chunk.toString();
    });
    child.on("exit", () => {
      try {
        resolve(JSON.parse(stdout));
      } catch {
        resolve(null);
      }
    });
    child.on("error", () => resolve(null));
  });
}

function shouldWakeManager(validation) {
  if (!validation) return false;
  return (
    validation.validated === true ||
    validation.managerNeeded === true ||
    validation.retryExhausted === true
  );
}

export default function qManagerChildExtension(pi) {
  const key = Symbol.for("vamos.q_manager_child_extension.loaded");
  if (globalThis[key]) return;
  globalThis[key] = true;

  pi.on("agent_end", async () => {
    const produced = await runChildComplete();
    const validation =
      produced ||
      (await readJson(process.env.Q_MANAGER_VALIDATED_STATUS_PATH || ""));
    const status = {
      event: "agent_end",
      stage: process.env.Q_MANAGER_STAGE || "",
      childId: process.env.Q_MANAGER_CHILD_ID || "",
      managerRunId: process.env.Q_MANAGER_MANAGER_RUN_ID || "",
      stateFile: process.env.Q_MANAGER_STATE_FILE || "",
      planDir: process.env.Q_MANAGER_PLAN_DIR || "",
      sessionId:
        process.env.Q_MANAGER_SESSION_ID || process.env.SESSION_ID || "",
      sessionDir:
        process.env.Q_MANAGER_SESSION_DIR || process.env.SESSION_DIR || "",
      sessionPath: process.env.SESSION_PATH || "",
      finishedAt: new Date().toISOString(),
      wakeTarget: process.env.Q_MANAGER_PARENT_PANE || "",
      wakeMode: process.env.Q_MANAGER_WAKE_MODE || "validated-only",
      validationStatusPath: process.env.Q_MANAGER_VALIDATED_STATUS_PATH || "",
      activeChildGeneration: validation?.childGeneration || "",
      helperProducedStatus: produced !== null,
      managerWakeSuppressed: !shouldWakeManager(validation),
      wakeDeliveryMode: validation?.wake?.mode || "",
      wakeDeliveryReason: validation?.wake?.reason || "",
    };
    await writeJson(process.env.Q_MANAGER_STATUS_PATH, status);
    await touch(process.env.Q_MANAGER_DONE_PATH);
  });
}

	}
	return WriteNDJSON(
		out,
		Event{Type: "child_finished", Ref: childRef(state.ActiveChild)},
	)
}

func RunChildComplete(
	ctx context.Context,
	opts ChildCompletionOptions,
	d deps,
	out io.Writer,
) (*ChildCompletionStatus, error) {
	if strings.TrimSpace(opts.StateFile) == "" {
		return nil, errors.New("state-file is required")
	}
	out = ensureWriter(out)
	clock := d.Clock
	if clock == nil {
		clock = time.Now
	}
	store := stateStore(d, "", clock)
	state, err := store.Load(opts.StateFile)
	if err != nil {
		return nil, err
	}
	if state.ActiveChild == nil {
		return nil, errors.New("no active child to complete")
	}
	if strings.TrimSpace(opts.ChildID) != "" &&
		state.ActiveChild.ID != strings.TrimSpace(opts.ChildID) {
		return nil, fmt.Errorf(
			"active child %q does not match requested child %q",
			state.ActiveChild.ID,
			opts.ChildID,
		)
	}
	child := state.ActiveChild
	text, parseCtx, err := ReadChildResultText(state, ResultSourceOptions{})
	status := ChildCompletionStatus{
		ChildID:    child.ID,
		Attempt:    child.ValidationRetryCount,
		RetryLimit: invalidResultRetryLimit(state),
	}
	if err == nil {
		parseCtx.ExpectedNodeID = wruntime.NodeID(child.Stage)
		parsed, parseErr := ParseNormalizeValidateDecide(text, state, parseCtx)
		if parseErr == nil {
			status.Validated = true
			status.DeliveryID = childCompletionDeliveryID(*child, &parsed, false)
			status.Result = childCompletionResult(parsed.Result)
			status.NextChild = nextChildInfo(state, parsed.Decision.NextNodeID)
			status.ManagerNeeded = childCompletionManagerNeeded(status.Result.Status)
			status.Normalizations = parsed.Normalizations
			state.ActiveChild.LifecycleStatus = "completed"
			state.ActiveChild.LastDeliveryID = status.DeliveryID
			state, status.Wake, err = queueOrDeliverWake(
				ctx,
				opts.StateFile,
				state,
				status,
				d,
			)
			if err != nil {
				return nil, err
			}
		} else {
			err = parseErr
		}
	}
	if err != nil {
		if shouldRepromptAfterValidationError(
			state,
			ContinueOptions{
				StateFile: opts.StateFile,
				PlanDir:   state.CanonicalPlanDir,
				Stage:     child.Stage,
			},
			err,
		) {
			attempt := child.ValidationRetryCount + 1
			if repromptErr := continueReprompt(
				ctx,
				state,
				ContinueOptions{
					StateFile: opts.StateFile,
					PlanDir:   state.CanonicalPlanDir,
					Stage:     child.Stage,
				},
				d,
				io.Discard,
				err,
			); repromptErr != nil {
				return nil, repromptErr
			}
			latest, loadErr := store.Load(opts.StateFile)
			if loadErr != nil {
				return nil, loadErr
			}
			state = latest
			child = state.ActiveChild
			status.ChildID = child.ID
			status.Attempt = attempt
			status.RetryLimit = invalidResultRetryLimit(state)
			status.Reason = "retryable_invalid_result"
			status.Wake = WakeDeliveryInstruction{
				Mode:   "suppress",
				Reason: "retryable_invalid_result",
			}
		} else if isRetryExhaustedValidationError(
			state,
			ContinueOptions{
				StateFile: opts.StateFile,
				PlanDir:   state.CanonicalPlanDir,
				Stage:     child.Stage,
			},
			err,
		) {
			status.Validated = false
			status.ManagerNeeded = true
			status.RetryExhausted = true
			status.DeliveryID = childCompletionDeliveryID(*child, nil, true)
			status.Result = ChildCompletionResult{
				Stage:   child.Stage,
				Status:  "invalid_result",
				Summary: err.Error(),
			}
			status.Reason = err.Error()
			state.ActiveChild.LifecycleStatus = "awaiting_manager"
			state.ActiveChild.LastDeliveryID = status.DeliveryID
			state, status.Wake, err = queueOrDeliverWake(
				ctx,
				opts.StateFile,
				state,
				status,
				d,
			)
			if err != nil {
				return nil, err
			}
		} else {
			return nil, err
		}
	}
	if state.ActiveChild != nil &&
		strings.TrimSpace(state.ActiveChild.ValidationStatusPath) != "" {
		if writeErr := writeValidationStatus(
			state.ActiveChild.ValidationStatusPath,
			status,
		); writeErr != nil {
			return nil, writeErr
		}
	}
	if saveErr := store.Save(opts.StateFile, state); saveErr != nil {
		return nil, saveErr
	}
	if strings.EqualFold(opts.Output, "json") {
		enc := json.NewEncoder(out)
		enc.SetIndent("", "  ")
		if err := enc.Encode(status); err != nil {
			return nil, err
		}
	} else {
		if _, err := fmt.Fprintf(
			out,
			"child completion: %s\nwake: %s\n",
			status.Result.Status,
			status.Wake.Mode,
		); err != nil {
			return nil, err
		}
	}
	return &status, nil
}

func childCompletionResult(result wruntime.WorkflowResult) ChildCompletionResult {
	out := ChildCompletionResult{
		Stage:    string(result.SourceNodeID),
		Status:   string(result.Status),
		Outcome:  string(result.Outcome),
		Artifact: result.PrimaryArtifact,
		Summary:  result.Summary,
	}
	var parsed qrspi.Result
	if len(result.Raw) > 0 && json.Unmarshal(result.Raw, &parsed) == nil {
		out.PlanGoal = parsed.Summary.PlanGoal
		out.StageCompleted = parsed.Summary.StageCompleted
		out.KeyDecisions = parsed.Summary.KeyDecisions
		out.ChildPolicy = policySummary(qrspi.Policy{
			AdvanceMode:             parsed.Policy.AdvanceMode,
			AutoMode:                parsed.Policy.AutoMode,
			EnablePlanReviews:       parsed.Policy.EnablePlanReviews,
			InvalidResultRetryLimit: parsed.Policy.InvalidResultRetryLimit,
		})
	}
	return out
}

func childCompletionDeliveryID(
	child ChildRunRef,
	parsed *ParsedDecision,
	exhausted bool,
) string {
	parts := []string{child.ID, fmt.Sprintf("%d", child.Generation)}
	if exhausted || parsed == nil {
		parts = append(parts, "invalid_result")
	} else {
		parts = append(
			parts,
			string(parsed.Result.SourceNodeID),
			string(parsed.Result.Status),
			string(parsed.Result.Outcome),
			parsed.Result.PrimaryArtifact,
		)
	}
	return strings.Join(parts, ":")
}

func nextChildInfo(state ManagerState, node wruntime.NodeID) NextChildInfo {
	if node == "" {
		return NextChildInfo{}
	}
	info := NextChildInfo{
		Stage:     string(node),
		Cwd:       defaultContinueCwd(state, node),
		WorkingOn: nextChildWorkingOn(node),
	}
	if def, err := Definition(); err == nil {
		if graphNode, ok := def.Nodes[node]; ok {
			info.Skill = graphNode.Prompt.SkillPath
		}
	}
	return info
}

func nextChildWorkingOn(node wruntime.NodeID) string {
	switch node {
	case qrspi.NodeQuestion:
		return "Decompose the task into QRSPI research questions or follow-up questions."
	case qrspi.NodeResearch:
		return "Answer the research questions with factual codebase evidence."
	case qrspi.NodeDesign:
		return "Create or update design.md and make aligned assumptions unless truly blocked."
	case qrspi.NodeOutline:
		return "Create the structured implementation outline from approved design context."
	case qrspi.NodeReviewOutline:
		return "Review outline.md for readiness before plan creation."
	case qrspi.NodePlan:
		return "Expand the reviewed outline into tactical plan.md."
	case qrspi.NodeReviewPlan:
		return "Review plan.md for workspace/implementation readiness."
	case qrspi.NodeWorkspace:
		return "Prepare or confirm the implementation workspace and branch routing."
	case qrspi.NodeImplement:
		return "Execute the next implementation slice in the implementation workspace."
	case qrspi.NodeReviewImplementation:
		return "Review completed implementation and identify follow-up work or human-review readiness."
	case qrspi.NodeVerify:
		return "Run verification, inspect artifacts, and produce verify.md."
	case qrspi.NodeHumanReviewImplementation:
		return "Wait for final human implementation approval."
	default:
		return "Run the next graph-selected QRSPI stage."
	}
}

func childCompletionManagerNeeded(status string) bool {
	return status == string(wruntime.StatusNeedsHuman) ||
		status == string(wruntime.StatusBlocked) ||
		status == string(wruntime.StatusError) ||
		status == "invalid_result"
}

func queueOrDeliverWake(
	ctx context.Context,
	stateFile string,
	state ManagerState,
	status ChildCompletionStatus,
	d deps,
) (ManagerState, WakeDeliveryInstruction, error) {
	if status.Wake.Mode == "suppress" {
		return state, status.Wake, nil
	}
	if strings.TrimSpace(status.DeliveryID) == "" {
		return state, WakeDeliveryInstruction{
			Mode:   "suppress",
			Reason: "missing_delivery_id",
		}, nil
	}
	if state.Delivery.LastDeliveryID == status.DeliveryID {
		return state, WakeDeliveryInstruction{
			Mode:   "suppress",
			Reason: "duplicate_delivery",
		}, nil
	}
	payload := childCompletionWakePayload(stateFile, state, status)
	if strings.EqualFold(state.Delivery.Status, "compacting") {
		state.Delivery.QueuedWake = &QueuedWake{
			DeliveryID:      status.DeliveryID,
			ChildID:         status.ChildID,
			ChildGeneration: activeChildGeneration(state),
			Payload:         payload,
			QueuedAt:        time.Now().Format(time.RFC3339),
		}
		return state, WakeDeliveryInstruction{
			Mode:    "queue",
			Payload: payload,
			Reason:  "manager_compacting",
		}, nil
	}
	paneID := managerDeliveryPane(state)
	if paneID == "" {
		state.Delivery.QueuedWake = &QueuedWake{
			DeliveryID:      status.DeliveryID,
			ChildID:         status.ChildID,
			ChildGeneration: activeChildGeneration(state),
			Payload:         payload,
			QueuedAt:        time.Now().Format(time.RFC3339),
		}
		return state, WakeDeliveryInstruction{
