		child.ID = "manual-" + strings.Trim(strings.ReplaceAll(child.SessionID, "/", "-"), "-")
	}
	if state.ActiveChild != nil {
		child.TmuxPaneID = firstNonEmpty(child.TmuxPaneID, state.ActiveChild.TmuxPaneID)
